class BankAccount {
  private double balance;

  public BankAccount(double initial) {
    if (initial < 0) {
      this.balance = 0.0;
    } else {
      this.balance = initial;
    }
  }

  public void deposit(double amount) {
    if (amount > 0) {
      balance += amount;
    }
  }

  public boolean withdraw(double amount) {
    if (amount > 0 && amount <= balance) {
      balance -= amount;
      return true;
    }
    return false;
  }

  public double getBalance() { return balance; }

  @Override
  public String toString() { return String.format("$%.2f", balance); }
}

class Demo {
  public static void main(String[] args) {
    BankAccount acc = new BankAccount(100);
    acc.deposit(50);
    boolean ok = acc.withdraw(120);
    System.out.println("Withdraw success: " + ok);
    System.out.println("Balance: " + acc);
  }
}

import java.util.*;

abstract class Shape {
  abstract double area();
}

class Circle extends Shape {
  private final double r;
  public Circle(double r) { this.r = r; }
  @Override double area() { return Math.PI * r * r; }
}

class Rectangle extends Shape {
  private final double w, h;
  public Rectangle(double w, double h) { this.w = w; this.h = h; }
  @Override double area() { return w * h; }
}

class ShapeDemo {
  static double totalArea(List<Shape> shapes) {
    double sum = 0;
    for (Shape s : shapes) sum += s.area();
    return sum;
  }
  public static void main(String[] args) {
    List<Shape> shapes = new ArrayList<>();
    shapes.add(new Circle(2));
    shapes.add(new Rectangle(3, 4));
    System.out.println("Total area = " + totalArea(shapes));
  }
}

import java.util.*;

interface Playable { void play(); }

class Song implements Playable {
  private final String title;
  public Song(String title) { this.title = title; }
  public void play() { System.out.println("Playing song: " + title); }
}

class Podcast implements Playable {
  private final String episode;
  public Podcast(String episode) { this.episode = episode; }
  public void play() { System.out.println("Streaming podcast: " + episode); }
}

class MediaPlayer {
  private final List<Playable> queue = new ArrayList<>();
  public void add(Playable p) { queue.add(p); }
  public void playAll() { for (Playable p : queue) p.play(); }
}

class PlayerDemo {
  public static void main(String[] args) {
    MediaPlayer mp = new MediaPlayer();
    mp.add(new Song("CS106A Theme"));
    mp.add(new Podcast("OOP Basics"));
    mp.playAll();
  }
}
